mapper.select:
SELECT s.*, u.institution_id AS institutionId, i.institution_name AS institutionName, g.name AS className, g.grade AS grade FROM student s LEFT JOIN sys_tbuser u ON s.user_id = u.id LEFT JOIN institution i ON u.institution_id = i.id LEFT JOIN `group` g ON s.class_id = g.id
AND s.name LIKE CONCAT('%', #{param.name}, '%')
AND s.identity_id LIKE CONCAT('%', #{param.identityId}, '%')
AND s.gender = #{param.gender}
AND s.college LIKE CONCAT('%', #{param.college}, '%')
AND s.class_id = #{param.classId}
AND u.institution_id IN
#{id}
AND g.grade = #{param.grade}
AND s.position LIKE CONCAT('%', #{param.position}, '%')
AND s.account_status = #{param.accountStatus}
AND g.name LIKE CONCAT('%', #{param.className}, '%')
ORDER BY s.add_datetime
ASC DESC
